,p_static_id=>'new_1'
,p_seq=>10
,p_name=>'Promedio Acumulado'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT TO_CHAR(fecha,''YYYY-MM-DD'') AS label,',
'       ROUND(AVG(promedio_dia) OVER (ORDER BY fecha ROWS UNBOUNDED PRECEDING), 2) AS value',
'FROM (',
'    SELECT n.fecha AS fecha, AVG(n.valor_nota / c.escala_maxima * 100) AS promedio_dia',
'    FROM notas n',
'    JOIN criterios_de_evaluacion c ON c.codigo_nota = n.codigo_nota',
'    GROUP BY n.fecha',
')',
'ORDER BY fecha'))
,p_items_value_column_name=>'VALUE'
,p_items_label_column_name=>'LABEL'
,p_color=>'#2e86de'
