,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>50
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT numero,',
'       provincia,',
'       apellido,',
'       nombre,',
'       cedula,',
'       genero,',
'       avatar_url,',
'       prom_final AS "Promedio Final",',
'       notas,',
'       CASE WHEN notas IS NULL THEN ''<span class="t-Badge">Sin nota</span>''',
'            ELSE ''<span class="t-Badge t-Badge--'' ||',
'                 CASE WHEN notas IN (''A'',''B'') THEN ''success''',
'                      WHEN notas IN (''C'',''D'') THEN ''warning''',
'                      ELSE ''danger'' END || ''">'' || notas || ''</span>''',
'       END AS notas_badge,',
'       por_asis AS "Porcentaje asistencia",',
'       CASE WHEN prom_final IS NULL THEN ''<span class="t-Badge">Sin datos</span>''',
'            WHEN prom_final >= (SELECT AVG(prom_final) FROM v_estudiantes_proy_final WHERE prom_final IS NOT NULL)',
'                 THEN ''<span style="color:#2e7d32;font-weight:bold;">&#9650; +'' ||',
'                      TO_CHAR(ROUND(prom_final - (SELECT AVG(prom_final) FROM v_estudiantes_proy_final WHERE prom_final IS NOT NULL), 2)) || ''</span>''',
'            ELSE ''<span style="color:#c62828;font-weight:bold;">&#9660; -'' ||',
'                 TO_CHAR(ROUND((SELECT AVG(prom_final) FROM v_estudiantes_proy_final WHERE prom_final IS NOT NULL) - prom_final, 2)) || ''</span>''',
'       END AS tendencia',
'FROM v_estudiantes_proy_final'))
