,p_chart_id=>wwv_flow_imp.id(18544238068936579888)
,p_static_id=>'new_1'
,p_seq=>10
,p_name=>unistr('Promedio por R\00FAbrica')
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT r.nombre AS label,',
'       ROUND(AVG(n.valor_nota / c.escala_maxima * 100), 2) AS value',
'FROM notas n',
'JOIN criterios_de_evaluacion c ON c.codigo_nota = n.codigo_nota',
'JOIN rubrica r ON r.codigo_rubrica = c.codigo_nota',
'GROUP BY r.nombre',
'ORDER BY value DESC'))
,p_items_value_column_name=>'VALUE'
,p_items_label_column_name=>'LABEL'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
