,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ''Total de Estudiantes'' AS titulo, TO_CHAR(COUNT(*)) AS valor FROM v_estudiantes_proy_final',
'UNION ALL',
'SELECT ''Promedio del Curso'', TO_CHAR(ROUND(AVG(prom_final), 2)) FROM v_estudiantes_proy_final WHERE prom_final IS NOT NULL',
'UNION ALL',
'SELECT ''% Aprobados (evaluados)'', TO_CHAR(ROUND(SUM(CASE WHEN prom_final >= 61 THEN 1 ELSE 0 END) * 100 / COUNT(*), 2)) || ''%'' FROM v_estudiantes_proy_final WHERE prom_final IS NOT NULL',
'UNION ALL',
'SELECT ''Sin Notas Registradas'', TO_CHAR(COUNT(*)) FROM v_estudiantes_proy_final WHERE prom_final IS NULL'))
