,p_plug_name=>'Desglose Notas'
,p_static_id=>'desglose-notas'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>40
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT c.codigo_nota,',
'       c.descripcion,',
'              ROUND(AVG(n.valor_nota) * c.porcentaje / c.escala_maxima, 2) AS porcentaje,',
'                     ROUND(SUM(AVG(n.valor_nota) * c.porcentaje / c.escala_maxima) OVER (), 2) AS total',
'                     FROM   notas n',
'                     JOIN   criterios_de_evaluacion c ON c.codigo_nota = n.codigo_nota',
'                     WHERE  n.numero = :P20_DESGLOSE',
'                     GROUP  BY c.codigo_nota, c.descripcion, c.porcentaje, c.escala_maxima'))
