wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(51707582544978860767)
,p_plug_name=>'Desglose por Rubrica'
,p_static_id=>'desglose-por-rubrica'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>3372714138756020509
,p_plug_display_sequence=>20
,p_plug_grid_column_span=>10
,p_plug_display_column=>2
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH rendimiento AS (',
'    SELECT r.nombre AS titulo,',
'           AVG(n.valor_nota / c.escala_maxima * 100) AS valor',
'    FROM notas n',
'    JOIN criterios_de_evaluacion c ON c.codigo_nota = n.codigo_nota',
'    JOIN rubrica r ON r.codigo_rubrica = c.codigo_nota',
'    WHERE n.numero = :P20_DESGLOSE',
'    GROUP BY r.nombre',
')',
'SELECT titulo,',
'       ROUND(valor, 2) AS valor,',
'       ROUND(valor - AVG(valor) OVER (), 2) AS diferencia,',
'       CASE WHEN valor >= AVG(valor) OVER () THEN ''Success'' ELSE ''Danger'' END AS estado,',
'       CASE WHEN valor >= AVG(valor) OVER () THEN ''fa-solid fa-arrow-up'' ELSE ''fa-solid fa-arrow-down'' END AS icono',
'FROM rendimiento'))
,p_query_order_by_type=>'STATIC'
,p_query_order_by=>'valor DESC'
,p_template_component_type=>'REPORT'
,p_lazy_loading=>false
,p_plug_source_type=>'TMPL_THEME_42$METRIC_CARD'
,p_plug_query_num_rows=>15
