wwv_flow_imp_page.create_component_da_action(
 p_id=>wwv_flow_imp.id(14607719584900707615)
,p_button_id=>wwv_flow_imp.id(14607719346700707613)
,p_action_sequence=>10
,p_name=>'Calcular Detalle Notas'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_static_id=>'calcular-detalle-notas'
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'items_to_return', 'P20_DETALLE_NOTAS',
  'items_to_submit', 'P20_DESGLOSE',
  'language', 'PLSQL',
  'plsql_code', wwv_flow_string.join(wwv_flow_t_varchar2(
    'DECLARE',
    '  v_detalle VARCHAR2(4000);',
    'BEGIN',
    '  SELECT LISTAGG(detalle, '', '') WITHIN GROUP (ORDER BY detalle)',
    '  INTO   v_detalle',
    '  FROM (',
    '    SELECT c.descripcion || '': '' || ROUND(AVG(n.valor_nota) * c.porcentaje / c.escala_maxima, 2) AS detalle',
    '    FROM   notas n',
    '    JOIN   criterios_de_evaluacion c ON c.codigo_nota = n.codigo_nota',
    '    WHERE  n.numero = :P20_DESGLOSE',
    '    GROUP BY c.descripcion, c.porcentaje, c.escala_maxima',
    '  );',
    '',
    '  :P20_DETALLE_NOTAS := v_detalle;',
    'END;')),
  'show_processing', 'N',
  'suppress_change_event', 'N')).to_clob
,p_stop_execution_on_error=>true
,p_wait_for_result=>true
,p_created_on=>wwv_flow_imp.dz('20260705195754Z')
,p_updated_on=>wwv_flow_imp.dz('20260705195754Z')
,p_created_by=>'JOEL.ALE.LIDER@GMAIL.COM'
,p_updated_by=>'JOEL.ALE.LIDER@GMAIL.COM'
);
