,p_region_template_options=>'#DEFAULT#:t-Region--noPadding:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--stretch:t-Report--staticRowColors:t-Report--rowHighlight:t-Report--inline:t-Report--hideNoPagination'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT TO_CHAR(n.fecha,''YYYY-MM-DD'') AS fecha,',
'       c.descripcion,',
'              ROUND(n.valor_nota * c.porcentaje / c.escala_maxima, 2) AS notas,',
'                     ROUND(AVG(n.valor_nota * c.porcentaje / c.escala_maxima) OVER (), 2) AS total',
'                     FROM   notas n',
'                     JOIN   criterios_de_evaluacion c ON c.codigo_nota = n.codigo_nota',
'                     WHERE  n.codigo_nota = :P25_COD_NOTA',
'                     AND    n.numero      = :P20_DESGLOSE',
'                     ORDER  BY n.fecha'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
