,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ''Total de Estudiantes'' AS titulo, TO_CHAR(COUNT(*)) AS valor, 1 AS orden, ''fa fa-users'' AS icono, CAST(NULL AS VARCHAR2(20)) AS badge, CAST(NULL AS VARCHAR2(20)) AS badge_status FROM v_estudiantes_proy_final',
'UNION ALL',
'SELECT ''Promedio General'', TO_CHAR(ROUND(AVG(prom_final),2)), 2, ''fa fa-line-chart'', NULL, NULL FROM v_estudiantes_proy_final WHERE prom_final IS NOT NULL',
'UNION ALL',
'SELECT ''Asistencia Promedio'', TO_CHAR(ROUND(AVG(por_asis),1)) || ''%'', 3, ''fa fa-calendar-check-o'', NULL, NULL FROM v_estudiantes_proy_final WHERE por_asis IS NOT NULL',
'UNION ALL',
'SELECT ''Rubricas Activas'', TO_CHAR(COUNT(*)), 4, ''fa fa-clipboard'', NULL, NULL FROM RUBRICA',
'UNION ALL',
'SELECT ''Estudiantes Aprobados'', TO_CHAR(SUM(CASE WHEN prom_final>=70 THEN 1 ELSE 0 END)), 5, ''fa fa-check-circle'', ''Aprobados'', ''Success'' FROM v_estudiantes_proy_final WHERE prom_final IS NOT NULL',
'UNION ALL',
'SELECT ''Asistencia Baja'', TO_CHAR(SUM(CASE WHEN por_asis<75 THEN 1 ELSE 0 END)), 6, ''fa fa-exclamation-triangle'', ''Atencion'', ''Danger'' FROM v_estudiantes_proy_final WHERE por_asis IS NOT NULL',
'UNION ALL',
'SELECT ''Mejor Promedio'', TO_CHAR(ROUND(MAX(prom_final),2)), 7, ''fa fa-trophy'', ''Destacado'', ''Info'' FROM v_estudiantes_proy_final WHERE prom_final IS NOT NULL',
'ORDER BY orden'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_plug_query_num_rows_type=>'SCROLL'
,p_show_total_row_count=>false
